import{_ as e,o as t,c as a,a9 as s}from"./chunks/framework.D4xYp1Zt.js";const o="/images/your-ancestor-is-jellyfish/you.png",p="/images/your-ancestor-is-jellyfish/father.png",l="/images/your-ancestor-is-jellyfish/great-great-grandfather.png",n="/images/your-ancestor-is-jellyfish/medieval.png",i="/images/your-ancestor-is-jellyfish/hunter.png",h="/images/your-ancestor-is-jellyfish/adam.png",m="/images/your-ancestor-is-jellyfish/australopithicus.png",g="/images/your-ancestor-is-jellyfish/monkey.png",A="/images/your-ancestor-is-jellyfish/tree-rodent.png",c="/images/your-ancestor-is-jellyfish/rodent.png",f="/images/your-ancestor-is-jellyfish/lizard.png",u="/images/your-ancestor-is-jellyfish/lizard-fish.png",b="/images/your-ancestor-is-jellyfish/fish.png",_="/images/your-ancestor-is-jellyfish/worm.png",y="/images/your-ancestor-is-jellyfish/jellyfish.png",w="/images/your-ancestor-is-jellyfish/sponge.png",d="/images/your-ancestor-is-jellyfish/eukaryote.png",k="/images/your-ancestor-is-jellyfish/prokaryote.png",j="/images/your-ancestor-is-jellyfish/first-life.png",I="/images/your-ancestor-is-jellyfish/pinit_fg_en_rect_gray_20.png",Y=JSON.parse('{"title":"Meet Your Ancestors (All of Them)","description":"","frontmatter":{"title":"Meet Your Ancestors (All of Them)","titleZh":"认识你的祖先(全部)","date":"2013-12-18T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html","slug":"your-ancestor-is-jellyfish"},"headers":[],"relativePath":"posts/your-ancestor-is-jellyfish.md","filePath":"posts/your-ancestor-is-jellyfish.md","lastUpdated":1782886257000}'),D={name:"posts/your-ancestor-is-jellyfish.md"};function v(U,r,G,P,T,H){return t(),a("div",null,[...r[0]||(r[0]=[s('<h1 id="认识你的祖先-全部-·-meet-your-ancestors-all-of-them" tabindex="-1">认识你的祖先(全部) · Meet Your Ancestors (All of Them) <a class="header-anchor" href="#认识你的祖先-全部-·-meet-your-ancestors-all-of-them" aria-label="Permalink to &quot;认识你的祖先(全部) · Meet Your Ancestors (All of Them)&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html</a> · 2013-12-18</p></blockquote><p>在你开始读这篇文章的时候,我们先列一些你已经很久没问过自己的问题:</p><p>—— 我为什么存在?</p><p>—— 我为什么长成这个样子?</p><p>—— 那些让我成为我的基因,是从哪儿来的?如果我把这些基因一路往回追溯得足够远,事情是不是会开始变得超级诡异,诡异到需要一系列 Wait But Why 水准低劣的插图才能讲清楚?</p><p>为了把事情弄个明白,我们从现在开始一步步往回走,沿途追踪一下我们的基因在每个重要阶段的样子。</p><p>我们从你开始。我不认识你,但我打赌你大概长这样:</p><p><a href="https://2.bp.blogspot.com/--1Hk5DzsAhM/UrFKYZeP4bI/AAAAAAAAGxs/6sflfanpouU/s1600/you.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>为了简化问题,我们只沿着你的父系血脉,也就是你 DNA 里的男性谱系走。</p><p>那么往回退一步,我们看到了<strong>你的父亲</strong>:</p><p><a href="https://4.bp.blogspot.com/-lkvkKVnxHvE/UrDELYwDg8I/AAAAAAAAGsc/KbWDJIOlFb0/s1600/father.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>然后我们再退到你的祖父、曾祖父,最后到你的高祖父,他大概出生在 1825 到 1875 年之间。他长这样:</p><p><a href="https://3.bp.blogspot.com/-ybXpimQ20Vs/UrDv_RBWkfI/AAAAAAAAGvQ/CaW2g1dUzbg/s1600/great+great+grandfather.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>你的高祖父这辈子大部分时间都没有自来水,也没有电,而且他很可能比你更种族歧视。你从没见过他,但没有他,就没有你。</p><p>现在我们再往回走,到他的父亲、他父亲的父亲,以此类推——我们直接往回跳 18 代,来到你的 [第 20 代] 曾祖父(我们把「曾」的次数用上标数字表示):</p><p><a href="https://4.bp.blogspot.com/-1gfhFco18pU/UrDwBd_caEI/AAAAAAAAGv4/vDibGKOtXdY/s1600/medieval.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>你的曾<sup>20</sup> 祖父活得非常真实。他不折磨别人的时候,就在被别人折磨。他没在染上黑死病等死的时候,就在十字军东征里屠杀妇女儿童。而且诡异的是,他可能跟你姓同一个姓。</p><p>如果他能见到你,他会被你现在这种娇气得要命的生活方式震撼到不行。但还不如你的曾<sup>500</sup> 祖父被震撼得那么厉害。</p><p><a href="https://1.bp.blogspot.com/-mgp5J4w0CwM/UrDv_vpQb3I/AAAAAAAAGvY/NcyDRF0w22o/s1600/hunter.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>你的曾<sup>500</sup> 祖父可没花好几年时间纠结哪个职业最能表达他的内心追求。他打猎、跟别的部落打仗,然后在 30 岁出头就死掉了,好歹在死之前设法让某个人怀了孕。要是他没做到,你还有今天几百万其他人,就都不会存在。</p><p><a href="https://3.bp.blogspot.com/-CQpVovTIMoc/UrDv9B5Z-9I/AAAAAAAAGus/IpFl_t1Z7L8/s1600/adam.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>现在我们来到了人类还不算完全是人类的时代,那个时代有一位非常特别的男人。科学家把他称为 <a href="https://www.sciencenews.org/article/y-chromosome-analysis-moves-adam-closer-eve" target="_blank" rel="noreferrer">Y 染色体亚当 (Y-chromosomal Adam)</a>。Y 染色体亚当是所有现存人类共同的最近男性祖先——换句话说,他不仅仅是你的曾14,000 祖父,他是<em>所有人的曾14,000 祖父</em>,是历史上最后一次所有人拥有共同男性祖先的时刻。从这一点往后我们讨论的所有祖先,都是全人类共同的祖先。</p><p>那么 Y 染色体亚当是个什么样的人?他是一个恶心透顶、极其令人不快的家伙,很可能强奸过人。但对我们大家来说,好消息是他活了下来,而且活得够久,把基因传了下去。如果他没能活下来,人类大概还是会存活,但现在的世界会完全不同,而我们没有一个人会存在。</p><p><a href="https://1.bp.blogspot.com/-1OA12M8f4qI/UrDwEsbMkGI/AAAAAAAAGww/dHiFhzxoQzQ/s1600/australopithicus.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>好了,现在事情开始变得诡异了。300 万年前,还没有人类。那个时代我们的祖先是猿和人的某种混合体,叫做南方古猿 (Australopithecus)。你的曾220,000 祖父不是什么高级智慧生物——他的大脑只有人类大脑的 35% 大——而且他<a href="http://img1.wikia.nocookie.net/__cb20101126190558/prehistoricearth/images/b/b1/Australopithecus.jpg" target="_blank" rel="noreferrer">长得也不咋地</a>。但他是你最早的几位能双足行走的祖先之一,也就是说他能直立站着——这让他能腾出手来干别的事,比如制造和使用工具,而这又让最聪明的个体得以繁盛,从而推动了更大脑袋的快速进化。</p><p><a href="https://1.bp.blogspot.com/-FfPnGkzoUIE/UrDwBhTtL4I/AAAAAAAAGv8/cQcPzMrzGE0/s1600/monkey.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>你的曾550,000 祖父是一只非常重要的猴子。他不仅是每一个活着的人类的祖先,也是每一只活着的黑猩猩的祖先。这是历史上我们最后一次和黑猩猩共享祖先——科学家们认为大约 600 万年前,人族 (Hominini) 分成了两支,最终分别演化成了人类和黑猩猩。这意味着大约在那时,存在着<em>一只猴子</em>——他有一个孩子后来成了所有人类的祖先,另一个孩子成了所有黑猩猩的祖先。</p><p><a href="https://2.bp.blogspot.com/-Bn1HC6ipqDQ/UrDwDcXgYRI/AAAAAAAAGwc/pqRtH7ll6Bk/s1600/tree+rodent.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>跟他大多数后代不一样,你的一千五百万代高祖父生不逢时,跟恐龙生活在同一个年代。在大约 6600 万年前那颗巨大的小行星导致恐龙灭绝之前,哺乳动物都是些体型小小的二等公民,主要活动范围仅限于树上。这位其貌不扬的家伙,是所有现代灵长类动物的共同祖先。</p><p><a href="https://1.bp.blogspot.com/-5bjr750F9_8/UrDwCGbMefI/AAAAAAAAGwM/jZsUwQ3zfWU/s1600/rodent.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>我希望你花点时间消化一下这个事实:你的五千五百万代高祖父是一只啮齿类动物。更具体地说,他是一种真兽类 (Eutherian) —— 第一种有胎盘的哺乳动物,是除了有袋类和产卵类之外所有哺乳动物的祖先。所以如果外面有哪条鲸鱼开着类似的博客,打算写一篇像这样追溯自己父系祖先的文章,那么在这之前他得自己想办法,但从这里开始他可以直接抄袭我这篇,因为对鲸鱼来说也完全适用。</p><p><a href="https://3.bp.blogspot.com/-fbb7yEqfGSM/UrDwAs55--I/AAAAAAAAGvo/UVw8131K9oQ/s1600/lizard.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>你的一亿两千五百万代高祖父在看到马陆时,不像正常人那样尖叫、扔本书过去然后拔腿就跑——他直接把它<em>吃</em>了。他是一种早期的蜥蜴,是我们这一支血脉里第一个拥有像样的胳膊、腿和高级神经系统的祖先——他也是所有哺乳动物、爬行动物和鸟类最后一次共享同一个祖先的时刻。(在他和我们那位啮齿类祖先之间,还夹着一个尴尬的过渡物种——第一种哺乳动物,它下蛋,就像今天的鸭嘴兽一样。)</p><p><a href="https://1.bp.blogspot.com/-DxpZ2BdrsvI/UrETlQfPEfI/AAAAAAAAGxM/329FMt-xL8o/s1600/lizard-fish.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>你的一亿六千万代高祖父讨厌他的生活。他是我们父系家族里第一个冒险离开海洋的成员,在进化史上相当于那些移民到新国家的现代人,抛下自己熟悉的一切,从零开始,只因为长远来看这对整个家族最好。用「走路」来形容你的一亿六千万代高祖父在陆地远征时的动作实在是太抬举他了——他其实是可怜兮兮地把自己<em>拖</em>过泥地,呼吸都费劲,而这一切只是为了让你有朝一日能生活在冰冷黑暗的海洋地狱之外。</p><p>他叫做棘螈 (Acanthostega) —— 他开创了一系列关键的现代特征,包括除了鳃之外还有肺,以及鳍里长了骨头——这一创新让他的后代长出了胳膊和腿。</p><p><a href="https://3.bp.blogspot.com/-5e2ZellHA_8/UrE-P7r-4vI/AAAAAAAAGxc/95kaXeIaeno/s1600/fish.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>你的 2.2 亿代曾祖父是一条鱼。看看你的胳膊和腿,再看看这张图——你的四肢只不过是这两对小破鳍的进化升级版。如果史前鱼类当年为了在洋流里保持平衡而以不同的方式进化,今天的人体外形可能会截然不同。它的另一大成就是成为第一个长下巴的生物——之前的祖先都只有一个吸盘状的洞。</p><p><a href="https://4.bp.blogspot.com/-O5jOAeJLGZk/UrDwD-JE9qI/AAAAAAAAGw0/YLMP__J22i4/s1600/worm.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>如果你的 2.55 亿代曾祖父看起来像一条丢人现眼的扁虫,那是因为他就是——但他有两项功劳:发明了大脑,并且是第一个具有两侧对称结构(有前后之分)的动物。</p><p><a href="https://2.bp.blogspot.com/-H9al2OaDk0c/UrDwAItRZHI/AAAAAAAAGvc/rf9PyMlpZt0/s1600/jellyfish.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p>我也不知道该怎么跟你说。这就是你家谱的一部分。</p><p>我想让你停下来想一秒钟,我可不是在瞎编——把你的父亲,和你父亲的父亲,这样倒推 4.35 亿次,你最终会得到一只水母。进化真是<em>匪夷所思</em>。</p><p>但我们别在没给水母应有的功劳前就跳过它——它带来了两大创新:神经和肌肉。眼睛也是大约在这个时期首次出现的,某个理论认为这正是寒武纪大爆发(动物生命突然爆发出多样性)的主要原因之一。</p><p><a href="https://3.bp.blogspot.com/-kUaFEItrH1Q/UrDwDIkrlqI/AAAAAAAAGwY/dg3dFrSIOgM/s1600/sponge.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>你的 5.55 亿代曾祖父是一块海绵,一辈子无聊得要死。</p><p>不过它帽子上确实插了一根大羽毛:它是世界上第一只动物。在它之前,所有生命都是单细胞生物,而它是第一个由多细胞组成的生物。</p><p>对,那时候还没有那些植物,它们本不该出现在图里。但我刚才才意识到这一点,而我为自己画出了它们感到很自豪,所以就让它们留在那儿了。</p><p><a href="https://1.bp.blogspot.com/-vdEeWTjH27k/UrDv9FlrjHI/AAAAAAAAGuw/ZlkY3h04f5g/s1600/eukaryote.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>我们得往回倒非常非常多代,才能见到你的 1000 亿代曾祖父,一个复杂的单细胞真核生物。</p><p>它看起来可能其貌不扬,但它既是整个动物界的祖先,又是性的发明者。而且它还挺可爱的。</p><p><a href="https://4.bp.blogspot.com/-hyKsuCzwVW8/UrDwCHN32sI/AAAAAAAAGwQ/al1v_dbJY_g/s1600/prokaryote.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p>再往回,<em>非常非常</em>久远地回到地球早期,我们见到了你的 8500 亿代曾祖父——一个毫无个人魅力的可怜巴巴的简单细胞细菌。它的最高成就是发明了光合作用,让大气中充满了氧气,为现代生命的存在铺平了道路。</p><p><a href="https://1.bp.blogspot.com/-cKKd8RPKR-Q/UrDv-j_01lI/AAAAAAAAGvI/PlCMB_LLdXU/s1600/first+life.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p>回溯 1.15 万亿代、大约 38 亿年,我们抵达了这条家谱的尽头——第一个有生命的粒子,地球上一切生命的开创者。我们并不是很清楚他一开始究竟是怎么活起来的——这是我们这个时代最重大的科学问题之一。相关的理论有不少,包括自然发生说、从原始汤 (primordial soup) 中涌现,甚至有人认为他是从宇宙别的地方来到地球的。不管怎样,我们欠他太多了,我们应该花一点时间,去感念 38 亿年前他那孤独的生命瞬间——正是它,催生了我们今天所知的一切。</p><p>作为收尾,有两件事值得回味:</p><p><strong>1) 你的基因故事有多丰富。</strong> 你的基因走过了<em>漫长</em>的路,穿越了<em>万亿</em>个其他生物体,经历了数量惊人的最优突变,才终于打包在你的染色体里汇聚一处。你之所以是你,是因为那只水母、那只蜥蜴、那只猴子身上发生过的事,以及它们几十亿年来各自适应环境的方式。</p><p>我读到过,我们打嗝其实是鱼类身上一种史前冲动的遗留物——当你的身体做出某个动作、产生某种感觉时,它就是一扇窗,让你窥见自己与所有这些其他物种、与生命史之间深深交织的联系。</p><h2 id="_2-你能存在-是多么不可思议的小概率事件。-从第一个生命粒子算起-超过一万亿位父亲和父亲的父亲一路传下来-最终才有你的父母孕育出你。而只要那些父亲-或母亲-中的任何一位在生育之前就死去了——只要你血脉中数以百万计的鱼里-任何一条被过早吃掉-只要你血脉中数以百万计的啮齿类里-任何一只在幼年时被一棵倒下的树压死——你就不会存在。可能会有一个跟你相似的人存在——但不是你。" tabindex="-1"><strong>2) 你能存在,是<em>多么</em>不可思议的小概率事件。</strong> 从第一个生命粒子算起,超过一万亿位父亲和父亲的父亲一路传下来,最终才有你的父母孕育出你。而只要<em>那些父亲(或母亲)中的任何一位在生育之前就死去了</em>——只要你血脉中数以百万计的鱼里,任何一条被过早吃掉;只要你血脉中数以百万计的啮齿类里,任何一只在幼年时被一棵倒下的树压死——你就不会存在。可能会有一个跟你相似的人存在——但不是你。 <a class="header-anchor" href="#_2-你能存在-是多么不可思议的小概率事件。-从第一个生命粒子算起-超过一万亿位父亲和父亲的父亲一路传下来-最终才有你的父母孕育出你。而只要那些父亲-或母亲-中的任何一位在生育之前就死去了——只要你血脉中数以百万计的鱼里-任何一条被过早吃掉-只要你血脉中数以百万计的啮齿类里-任何一只在幼年时被一棵倒下的树压死——你就不会存在。可能会有一个跟你相似的人存在——但不是你。" aria-label="Permalink to &quot;**2) 你能存在,是*多么*不可思议的小概率事件。** 从第一个生命粒子算起,超过一万亿位父亲和父亲的父亲一路传下来,最终才有你的父母孕育出你。而只要*那些父亲(或母亲)中的任何一位在生育之前就死去了*——只要你血脉中数以百万计的鱼里,任何一条被过早吃掉;只要你血脉中数以百万计的啮齿类里,任何一只在幼年时被一棵倒下的树压死——你就不会存在。可能会有一个跟你相似的人存在——但不是你。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>如果你喜欢这篇,不妨接着看这些:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html" target="_blank" rel="noreferrer">你的家族:过去、现在和未来 (Your Family: Past, Present, and Future)</a></strong> —— 家谱一下子就会变得超级复杂</p><p><strong><a href="https://waitbutwhy.com/2016/01/horizontal-history.html" target="_blank" rel="noreferrer">横向历史 (Horizontal History)</a></strong> —— 从另一个角度看历史</p><h2 id="灵长类颁奖典礼-the-primate-awards-——-关于你的祖先-你不知道的还有很多" tabindex="-1"><strong><a href="https://waitbutwhy.com/2013/10/the-primate-awards.html" target="_blank" rel="noreferrer">灵长类颁奖典礼 (The Primate Awards)</a></strong> —— 关于你的祖先,你不知道的还有很多 <a class="header-anchor" href="#灵长类颁奖典礼-the-primate-awards-——-关于你的祖先-你不知道的还有很多" aria-label="Permalink to &quot;**[灵长类颁奖典礼 (The Primate Awards)](https://waitbutwhy.com/2013/10/the-primate-awards.html)** —— 关于你的祖先,你不知道的还有很多&quot;">​</a></h2><p><strong>关于我是怎么算出每种情况下“great”数量的说明:</strong></p><p>我的做法是,根据沿途各个物种的典型寿命和性成熟年龄,粗略估算了世代长度。人类世代取 25 年,南方古猿和高等灵长类取 13 年,早期树栖灵长类取 5 年,啮齿类、蜥蜴、鱼类和蠕虫取 2 年,水母和海绵取 2 个月,单细胞生物取 1 天。</p><p><strong>资料来源</strong> – Toth, Nicholas and Schick, Kathy (2005). “African Origins” in <em>The Human Past: World Prehistory and the Development of Human Societies</em> (Editor: Chris Scarre). London: Thames and Hudson. Page 60. – Richard Dawkins 2004 <em>The Ancestor&#39;s Tale</em> page 136, 250, and 289. – A Jurassic eutherian mammal and divergence of marsupials and placentals <a href="http://dx.doi.org/10.1038/nature10291" target="_blank" rel="noreferrer">http://dx.doi.org/10.1038/nature10291</a> – Eckhart L, Valle LD, Jaeger K, et al. (November 2008). <em>Proceedings of the National Academy of Sciences of the United States of America</em> 105 (47): 18419–23. – <a href="http://web.archive.org/web/20090319201312/http://www.uhh.hawaii.edu/~ronald/392/Homol-Gill-Jaw.JPG" target="_blank" rel="noreferrer">http://web.archive.org/web/20090319201312/http://www.uhh.hawaii.edu/~ronald/392/Homol-Gill-Jaw.JPG</a> – <a href="http://www.ucmp.berkeley.edu/protista/proterospongia.html" target="_blank" rel="noreferrer">http://www.ucmp.berkeley.edu/protista/proterospongia.html</a> – 当然,还有一大堆维基百科,不过既然那「不够专业」,我们就当它没参与过好了。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html&amp;description=Meet%20Your%20Ancestors%20(All%20of%20Them)" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p>',71)])])}const E=e(D,[["render",v]]);export{Y as __pageData,E as default};
